import{_ as t,c as n,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Versionshistorie: Funktionsentwicklung | opencode-agent-skills","description":"Erfahren Sie mehr über die Versionsentwicklung des OpenCode Agent Skills Plugins. Dieses Tutorial fasst alle wichtigen Funktionsaktualisierungen, Bug-Fixes, Architekturverbesserungen und Breaking Changes von v0.1.0 bis v0.6.4 zusammen.","frontmatter":{"title":"Versionshistorie: Funktionsentwicklung | opencode-agent-skills","sidebarTitle":"Was ist neu in der Version","subtitle":"Versionshistorie","description":"Erfahren Sie mehr über die Versionsentwicklung des OpenCode Agent Skills Plugins. Dieses Tutorial fasst alle wichtigen Funktionsaktualisierungen, Bug-Fixes, Architekturverbesserungen und Breaking Changes von v0.1.0 bis v0.6.4 zusammen.","tags":["Versionsupdate","Changelog","Veröffentlichungshistorie"],"order":3},"headers":[],"relativePath":"de/joshuadavidthomas/opencode-agent-skills/changelog/index.md","filePath":"de/joshuadavidthomas/opencode-agent-skills/changelog/index.md"}'),a={name:"de/joshuadavidthomas/opencode-agent-skills/changelog/index.md"};function s(l,e,d,o,u,h){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="versionshistorie" tabindex="-1">Versionshistorie <a class="header-anchor" href="#versionshistorie" aria-label="Permalink to &quot;Versionshistorie&quot;">​</a></h1><p>Dieses Dokument zeichnet alle Versionsaktualisierungen des OpenCode Agent Skills Plugins auf. Durch die Versionshistorie können Sie den Entwicklungspfad der Funktionen, behobene Probleme und Architekturverbesserungen nachvollziehen.</p><div class="tip custom-block"><p class="custom-block-title">Aktuelle Version</p><p>Die neueste stabile Version ist <strong>v0.6.4</strong> (2026-01-20)</p></div><h2 id="versions-zeitleiste" tabindex="-1">Versions-Zeitleiste <a class="header-anchor" href="#versions-zeitleiste" aria-label="Permalink to &quot;Versions-Zeitleiste&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Veröffentlichungsdatum</th><th>Typ</th><th>Hauptinhalt</th></tr></thead><tbody><tr><td>0.6.4</td><td>2026-01-20</td><td>Fix</td><td>YAML-Parsing, Claude v2-Unterstützung</td></tr><tr><td>0.6.3</td><td>2025-12-16</td><td>Verbesserung</td><td>Skill-Empfehlungshinweise optimiert</td></tr><tr><td>0.6.2</td><td>2025-12-15</td><td>Fix</td><td>Skill-Namen von Verzeichnisnamen getrennt</td></tr><tr><td>0.6.1</td><td>2025-12-13</td><td>Verbesserung</td><td>Doppelempfehlung geladener Skills vermieden</td></tr><tr><td>0.6.0</td><td>2025-12-12</td><td>Neue Funktion</td><td>Semantischer Matching, Embedding-Vorabkalkulation</td></tr><tr><td>0.5.0</td><td>2025-12-11</td><td>Verbesserung</td><td>Fuzzy-Matching-Vorschläge, Refactoring</td></tr><tr><td>0.4.1</td><td>2025-12-08</td><td>Verbesserung</td><td>Installationsmethode vereinfacht</td></tr><tr><td>0.4.0</td><td>2025-12-05</td><td>Verbesserung</td><td>Skript-Rekursivsuche</td></tr><tr><td>0.3.3</td><td>2025-12-02</td><td>Fix</td><td>Symlink-Verarbeitung</td></tr><tr><td>0.3.2</td><td>2025-11-30</td><td>Fix</td><td>Agent-Modus beibehalten</td></tr><tr><td>0.3.1</td><td>2025-11-28</td><td>Fix</td><td>Modellwechsel-Problem</td></tr><tr><td>0.3.0</td><td>2025-11-27</td><td>Neue Funktion</td><td>Dateilisten-Funktion</td></tr><tr><td>0.2.0</td><td>2025-11-26</td><td>Neue Funktion</td><td>Superpowers-Modus</td></tr><tr><td>0.1.0</td><td>2025-11-26</td><td>Initial</td><td>4 Tools, mehrfache Erkennung</td></tr></tbody></table><h2 id="detailliertes-anderungsprotokoll" tabindex="-1">Detailliertes Änderungsprotokoll <a class="header-anchor" href="#detailliertes-anderungsprotokoll" aria-label="Permalink to &quot;Detailliertes Änderungsprotokoll&quot;">​</a></h2><h3 id="v0-6-4-2026-01-20" tabindex="-1">v0.6.4 (2026-01-20) <a class="header-anchor" href="#v0-6-4-2026-01-20" aria-label="Permalink to &quot;v0.6.4 (2026-01-20)&quot;">​</a></h3><p><strong>Behoben</strong>:</p><ul><li>YAML-Frontmatter-Parsing für mehrzeilige Skill-Beschreibungen behoben (unterstützt <code>|</code> und <code>&gt;</code> Blockskalarsyntax), indem der benutzerdefinierte Parser durch die <code>yaml</code>-Bibliothek ersetzt wurde</li><li>Unterstützung für das Claude-Plugin-v2-Format hinzugefügt, <code>installed_plugins.json</code> verwendet nun ein Plugin-Installationsarray statt eines einzelnen Objekts</li></ul><p><strong>Verbessert</strong>:</p><ul><li>Claude Code Plugin-Cache-Discovery unterstützt nun die neue verschachtelte Verzeichnisstruktur (<code>cache/&lt;marketplace&gt;/&lt;plugin&gt;/&lt;version&gt;/skills/</code>)</li></ul><h3 id="v0-6-3-2025-12-16" tabindex="-1">v0.6.3 (2025-12-16) <a class="header-anchor" href="#v0-6-3-2025-12-16" aria-label="Permalink to &quot;v0.6.3 (2025-12-16)&quot;">​</a></h3><p><strong>Verbessert</strong>:</p><ul><li>Skill-Auswertungshinweise optimiert, um zu verhindern, dass das Modell &quot;Kein Skill erforderlich&quot;-Nachrichten an den Benutzer sendet (Benutzer sehen die versteckten Auswertungshinweise nicht)</li></ul><h3 id="v0-6-2-2025-12-15" tabindex="-1">v0.6.2 (2025-12-15) <a class="header-anchor" href="#v0-6-2-2025-12-15" aria-label="Permalink to &quot;v0.6.2 (2025-12-15)&quot;">​</a></h3><p><strong>Behoben</strong>:</p><ul><li>Skill-Validierung erlaubt nun, dass Verzeichnisnamen von dem <code>name</code> in der SKILL.md-Frontmatter abweichen. Der <code>name</code> in der Frontmatter ist der Standardbezeichner, der Verzeichnisname dient nur zur Organisation. Dies entspricht der Anthropic Agent Skills-Spezifikation.</li></ul><h3 id="v0-6-1-2025-12-13" tabindex="-1">v0.6.1 (2025-12-13) <a class="header-anchor" href="#v0-6-1-2025-12-13" aria-label="Permalink to &quot;v0.6.1 (2025-12-13)&quot;">​</a></h3><p><strong>Verbessert</strong>:</p><ul><li>Die dynamische Skill-Empfehlung verfolgt nun pro Sitzung bereits geladene Skills und vermeidet Doppelempfehlung bereits geladener Skills, was redundante Hinweise und Kontextnutzung reduziert</li></ul><h3 id="v0-6-0-2025-12-12" tabindex="-1">v0.6.0 (2025-12-12) <a class="header-anchor" href="#v0-6-0-2025-12-12" aria-label="Permalink to &quot;v0.6.0 (2025-12-12)&quot;">​</a></h3><p><strong>Neu</strong>:</p><ul><li><strong>Semantisches Skill-Matching</strong>: Nach der anfänglichen Skill-Listeneinblendung werden nachfolgende Nachrichten mit lokalen Embeddings mit den Skill-Beschreibungen abgeglichen</li><li><code>@huggingface/transformers</code>-Abhängigkeit für lokale Embedding-Generierung hinzugefügt (quantisierte Version von all-MiniLM-L6-v2)</li><li>Wenn Nachrichten verfügbare Skills entsprechen, wird ein 3-Schritte-Auswertungshinweis eingefügt (EVALUATE → DECIDE → ACTIVATE), der zum Laden der Skills anregt (inspiriert von <a href="https://github.com/spences10" target="_blank" rel="noreferrer">@spences10</a>s <a href="https://scottspence.com/posts/how-to-make-claude-code-skills-activate-reliably" target="_blank" rel="noreferrer">Blogpost</a>)</li><li>Embeddings auf der Festplatte zwischengespeichert für Matching mit geringer Latenz (~/.cache/opencode-agent-skills/)</li><li>Sitzungen beim <code>session.deleted</code>-Event bereinigt</li></ul><h3 id="v0-5-0-2025-12-11" tabindex="-1">v0.5.0 (2025-12-11) <a class="header-anchor" href="#v0-5-0-2025-12-11" aria-label="Permalink to &quot;v0.5.0 (2025-12-11)&quot;">​</a></h3><p><strong>Neu</strong>:</p><ul><li>&quot;Meinten Sie...&quot; Fuzzy-Matching-Vorschläge zu allen Tools hinzugefügt (<code>use_skill</code>, <code>read_skill_file</code>, <code>run_skill_script</code>, <code>get_available_skills</code>)</li></ul><p><strong>Verbessert</strong>:</p><ul><li><strong>Breaking Change</strong>: Das Tool <code>find_skills</code> in <code>get_available_skills</code> umbenannt, um die Absicht klarer zu machen</li><li><strong>Intern</strong>: Die Codebasis in unabhängige Module reorganisiert (<code>claude.ts</code>, <code>skills.ts</code>, <code>tools.ts</code>, <code>utils.ts</code>, <code>superpowers.ts</code>), um die Wartbarkeit zu verbessern</li><li><strong>Intern</strong>: Codequalität durch Entfernen von KI-generierten Kommentaren und unnötigem Code verbessert</li></ul><h3 id="v0-4-1-2025-12-08" tabindex="-1">v0.4.1 (2025-12-08) <a class="header-anchor" href="#v0-4-1-2025-12-08" aria-label="Permalink to &quot;v0.4.1 (2025-12-08)&quot;">​</a></h3><p><strong>Verbessert</strong>:</p><ul><li>Die Installationsmethode verwendet nun NPM-Pakete über die OpenCode-Konfiguration statt git clone + Symlink</li></ul><p><strong>Entfernt</strong>:</p><ul><li><code>INSTALL.md</code> entfernt (nach der Vereinfachung nicht mehr benötigt)</li></ul><h3 id="v0-4-0-2025-12-05" tabindex="-1">v0.4.0 (2025-12-05) <a class="header-anchor" href="#v0-4-0-2025-12-05" aria-label="Permalink to &quot;v0.4.0 (2025-12-05)&quot;">​</a></h3><p><strong>Verbessert</strong>:</p><ul><li>Die Skript-Erkennung durchsucht nun rekursiv das gesamte Skill-Verzeichnis (maximale Tiefe 10) statt nur das Stammverzeichnis und das <code>scripts/</code>-Unterverzeichnis</li><li>Skripte werden nun über relative Pfade (z. B. <code>tools/build.sh</code>) statt nur über Basisnamen identifiziert</li><li>Den Parameter <code>skill_name</code> in den Tools <code>read_skill_file</code>, <code>run_skill_script</code> und <code>use_skill</code> in <code>skill</code> umbenannt</li><li>Den Parameter <code>script_name</code> im Tool <code>run_skill_script</code> in <code>script</code> umbenannt</li></ul><h3 id="v0-3-3-2025-12-02" tabindex="-1">v0.3.3 (2025-12-02) <a class="header-anchor" href="#v0-3-3-2025-12-02" aria-label="Permalink to &quot;v0.3.3 (2025-12-02)&quot;">​</a></h3><p><strong>Behoben</strong>:</p><ul><li>Datei- und Verzeichniserkennung korrigiert, um Symlinks korrekt zu verarbeiten, indem <code>fs.stat</code> verwendet wird</li></ul><h3 id="v0-3-2-2025-11-30" tabindex="-1">v0.3.2 (2025-11-30) <a class="header-anchor" href="#v0-3-2-2025-11-30" aria-label="Permalink to &quot;v0.3.2 (2025-11-30)&quot;">​</a></h3><p><strong>Behoben</strong>:</p><ul><li>Beibehaltung des Agent-Modus beim Einfügen synthetischer Nachrichten am Sitzungsstart</li></ul><h3 id="v0-3-1-2025-11-28" tabindex="-1">v0.3.1 (2025-11-28) <a class="header-anchor" href="#v0-3-1-2025-11-28" aria-label="Permalink to &quot;v0.3.1 (2025-11-28)&quot;">​</a></h3><p><strong>Behoben</strong>:</p><ul><li>Unerwarteter Modellwechsel bei der Verwendung von Skill-Tools behoben, indem das aktuelle Modell explizit in der <code>noReply</code>-Operation übergeben wird (temporäre Lösung für opencode issue #4475)</li></ul><h3 id="v0-3-0-2025-11-27" tabindex="-1">v0.3.0 (2025-11-27) <a class="header-anchor" href="#v0-3-0-2025-11-27" aria-label="Permalink to &quot;v0.3.0 (2025-11-27)&quot;">​</a></h3><p><strong>Neu</strong>:</p><ul><li>Dateiliste zur <code>use_skill</code>-Ausgabe hinzugefügt</li></ul><h3 id="v0-2-0-2025-11-26" tabindex="-1">v0.2.0 (2025-11-26) <a class="header-anchor" href="#v0-2-0-2025-11-26" aria-label="Permalink to &quot;v0.2.0 (2025-11-26)&quot;">​</a></h3><p><strong>Neu</strong>:</p><ul><li>Unterstützung für Superpowers-Modus hinzugefügt</li><li>Veröffentlichungsnachweis hinzugefügt</li></ul><h3 id="v0-1-0-2025-11-26" tabindex="-1">v0.1.0 (2025-11-26) <a class="header-anchor" href="#v0-1-0-2025-11-26" aria-label="Permalink to &quot;v0.1.0 (2025-11-26)&quot;">​</a></h3><p><strong>Neu</strong>:</p><ul><li>Tool <code>use_skill</code> hinzugefügt, um Skill-Inhalte in den Kontext zu laden</li><li>Tool <code>read_skill_file</code> hinzugefügt, um unterstützende Dateien im Skill-Verzeichnis zu lesen</li><li>Tool <code>run_skill_script</code> hinzugefügt, um Skripte aus dem Skill-Verzeichnis auszuführen</li><li>Tool <code>find_skills</code> hinzugefügt, um verfügbare Skills zu suchen und aufzulisten</li><li>Mehrfache Skill-Erkennung hinzugefügt (Projektebene, Benutzerebene und Claude-kompatible Orte)</li><li>Frontmatter-Validierung gemäß Anthropic Agent Skills Spec v1.0 hinzugefügt</li><li>Automatische Skill-Listeneinblendung am Sitzungsstart und nach der Kontextkomprimierung hinzugefügt</li></ul><p><strong>Neue Mitwirkende</strong>:</p><ul><li>Josh Thomas <a href="mailto:josh@joshthomas.dev" target="_blank" rel="noreferrer">josh@joshthomas.dev</a> (Betreuer)</li></ul><h2 id="ubersicht-der-funktionsentwicklung" tabindex="-1">Übersicht der Funktionsentwicklung <a class="header-anchor" href="#ubersicht-der-funktionsentwicklung" aria-label="Permalink to &quot;Übersicht der Funktionsentwicklung&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funktion</th><th>eingeführt in Version</th><th>Entwicklungspfad</th></tr></thead><tbody><tr><td>4 Basis-Tools</td><td>v0.1.0</td><td>v0.5.0 Fuzzy-Matching hinzugefügt</td></tr><tr><td>Mehrfache Skill-Erkennung</td><td>v0.1.0</td><td>v0.4.1 Installation vereinfacht, v0.6.4 Claude v2-Unterstützung</td></tr><tr><td>Automatische Kontexteinfügung</td><td>v0.1.0</td><td>v0.3.0 Dateiliste hinzugefügt, v0.6.1 Doppelempfehlung vermieden</td></tr><tr><td>Superpowers-Modus</td><td>v0.2.0</td><td>Stabil</td></tr><tr><td>Skript-Rekursivsuche</td><td>v0.4.0</td><td>v0.3.3 Symlink-Fix</td></tr><tr><td>Semantisches Matching</td><td>v0.6.0</td><td>v0.6.1 Duplikate vermieden, v0.6.3 Hinweise optimiert</td></tr><tr><td>Fuzzy-Matching-Vorschläge</td><td>v0.5.0</td><td>Stabil</td></tr></tbody></table><h2 id="hinweise-zu-breaking-changes" tabindex="-1">Hinweise zu Breaking Changes <a class="header-anchor" href="#hinweise-zu-breaking-changes" aria-label="Permalink to &quot;Hinweise zu Breaking Changes&quot;">​</a></h2><h3 id="v0-6-0-semantisches-matching" tabindex="-1">v0.6.0: Semantisches Matching <a class="header-anchor" href="#v0-6-0-semantisches-matching" aria-label="Permalink to &quot;v0.6.0: Semantisches Matching&quot;">​</a></h3><p>Einführung der semantischen Matching-Fähigkeit basierend auf lokalen Embeddings, die es der KI ermöglicht, relevante Skills basierend auf dem Inhalt der Benutzernachrichten automatisch zu empfehlen, ohne dass der Benutzer die Skill-Namen manuell merken muss.</p><ul><li><strong>Technische Details</strong>: Verwendung des HuggingFace-Modells <code>all-MiniLM-L6-v2</code> (q8-quantisiert)</li><li><strong>Cache-Mechanismus</strong>: Embedding-Ergebnisse werden in <code>~/.cache/opencode-agent-skills/</code> zwischengespeichert, um die nachfolgende Matching-Geschwindigkeit zu erhöhen</li><li><strong>Matching-Ablauf</strong>: Benutzernachricht → Embedding → Kosinusähnlichkeit mit Skill-Beschreibungen berechnen → Top 5 Empfehlungen (Schwellenwert 0,35)</li></ul><h3 id="v0-5-0-refactoring-und-tool-umbenennung" tabindex="-1">v0.5.0: Refactoring und Tool-Umbenennung <a class="header-anchor" href="#v0-5-0-refactoring-und-tool-umbenennung" aria-label="Permalink to &quot;v0.5.0: Refactoring und Tool-Umbenennung&quot;">​</a></h3><p>Die Code-Architektur wurde zu einem modularen Design umgebaut, die Tool-Benennung ist nun klarer:</p><ul><li><code>find_skills</code> → <code>get_available_skills</code></li><li><code>skill_name</code> → <code>skill</code></li><li><code>script_name</code> → <code>script</code></li></ul><h3 id="v0-4-0-upgrade-des-skript-erkennungsmechanismus" tabindex="-1">v0.4.0: Upgrade des Skript-Erkennungsmechanismus <a class="header-anchor" href="#v0-4-0-upgrade-des-skript-erkennungsmechanismus" aria-label="Permalink to &quot;v0.4.0: Upgrade des Skript-Erkennungsmechanismus&quot;">​</a></h3><p>Die Skript-Erkennung wurde von &quot;nur Stammverzeichnis + scripts/&quot; auf &quot;rekursive Suche des gesamten Skill-Verzeichnisses&quot; (maximale Tiefe 10) hochgestuft, was eine flexiblere Skript-Organisation ermöglicht.</p><h3 id="v0-2-0-superpowers-integration" tabindex="-1">v0.2.0: Superpowers-Integration <a class="header-anchor" href="#v0-2-0-superpowers-integration" aria-label="Permalink to &quot;v0.2.0: Superpowers-Integration&quot;">​</a></h3><p>Unterstützung für den Superpowers-Workflow-Modus hinzugefügt, erfordert die Installation des <code>using-superpowers</code>-Skills und das Setzen der Umgebungsvariable <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code>.</p><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert am: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeile</th></tr></thead><tbody><tr><td>Aktuelle Versionsnummer</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/package.json#L3-L3" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>3</td></tr><tr><td>Versionshistorie</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/CHANGELOG.md#L19-L152" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td><td>19-152</td></tr></tbody></table><p><strong>Wichtige Versionsinformationen</strong>:</p><ul><li><code>v0.6.4</code>: Aktuelle Version (2026-01-20)</li><li><code>v0.6.0</code>: Semantisches Matching eingeführt (2025-12-12)</li><li><code>v0.5.0</code>: Refactoring-Version (2025-12-11)</li><li><code>v0.1.0</code>: Initialversion (2025-11-26)</li></ul></details>',72)])])}const k=t(a,[["render",s]]);export{g as __pageData,k as default};
